import React, { useState } from 'react';

function AddBookForm({ onSubmit, onCancel }) {
  const [title, setTitle] = useState('');
  const [author, setAuthor] = useState('');
  const [description, setDescription] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    onSubmit({ title, author, description, rating: 0, reviews: [] });
    setTitle('');
    setAuthor('');
    setDescription('');
  };

  return (
    <div className="card animate-fade-in">
      <div className="card-header">
        <div className="text-center">
          <div className="inline-flex items-center justify-center w-12 h-12 bg-success rounded-xl mb-4">
            <span className="text-xl">📚</span>
          </div>
          <h3 className="text-xl font-bold text-primary mb-2">Add New Book</h3>
          <p className="text-secondary">Expand your digital library</p>
        </div>
      </div>

      <div className="card-body">
        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label className="form-label">Book Title</label>
            <input
              type="text"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              className="form-input"
              placeholder="Enter book title"
              required
            />
          </div>

          <div>
            <label className="form-label">Author</label>
            <input
              type="text"
              value={author}
              onChange={(e) => setAuthor(e.target.value)}
              className="form-input"
              placeholder="Enter author name"
              required
            />
          </div>

          <div>
            <label className="form-label">Description (Optional)</label>
            <textarea
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              className="form-textarea"
              rows={3}
              placeholder="Brief description of the book..."
            />
          </div>

          <div className="flex gap-3">
            <button type="submit" className="btn btn-success flex-1">
              <svg className="icon-sm mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
              </svg>
              Add Book
            </button>

            <button type="button" onClick={onCancel} className="btn btn-secondary flex-1">
              Cancel
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

export default AddBookForm;
